int ui_spy_steal(struct game_s *g, int spy, int target, uint8_t flags_field)
{
    /* 1oom-mp: ask the spying human which tech field to steal (default 0 outside MP) */
    if (g_mp_decision_hook) {
        struct { int32_t spy, target; uint8_t flags; } rq;
        int32_t fld = 0;
        rq.spy = spy; rq.target = target; rq.flags = flags_field;
        int r = g_mp_decision_hook(spy, MP_DEC_SPY_STEAL, &rq, sizeof(rq), &fld, sizeof(fld));
        if (r >= (int)sizeof(fld)) { return fld; }
    }
    return 0;
}

