ui_sabotage_t ui_spy_sabotage_ask(struct game_s *g, int spy, int target, planet_id_t *planetptr)
{
    /* 1oom-mp: ask the spying human what to sabotage + where (default none outside MP) */
    if (g_mp_decision_hook) {
        struct { int32_t spy, target; } rq;
        struct { int32_t act; uint16_t planet; } rs = { 0, PLANET_NONE };
        rq.spy = spy; rq.target = target;
        int r = g_mp_decision_hook(spy, MP_DEC_SPY_SABOTAGE, &rq, sizeof(rq), &rs, sizeof(rs));
        if (r >= (int)sizeof(rs)) {
            if (planetptr) { *planetptr = (planet_id_t)rs.planet; }
            return (ui_sabotage_t)rs.act;
        }
    }
    if (planetptr) { *planetptr = PLANET_NONE; }
    return 0;
}

