/* 1oom-mp: the galactic-council vote + accept happen during resolution; ship the
   election state to the voting human's client and ask there (the struct's pointers
   are zeroed for transport and re-pointed client-side). Default outside MP unchanged. */
int ui_election_vote(struct election_s *el, int player_i)
{
    if (g_mp_decision_hook) {
        struct election_s e = *el;
        e.g = NULL; e.uictx = NULL; e.buf = NULL; e.str = NULL;
        uint8_t req[sizeof(struct election_s) + 4];
        int32_t pi32 = player_i, vote = 0;
        memcpy(req, &e, sizeof(e));
        memcpy(req + sizeof(e), &pi32, 4);
        int r = g_mp_decision_hook(player_i, MP_DEC_ELECTION_VOTE, req, (int)sizeof(req), &vote, sizeof(vote));
        if (r >= (int)sizeof(vote)) { return vote; }
    }
    return 0;
}

bool ui_election_accept(struct election_s *el, int player_i)
{
    if (g_mp_decision_hook) {
        struct election_s e = *el;
        e.g = NULL; e.uictx = NULL; e.buf = NULL; e.str = NULL;
        uint8_t req[sizeof(struct election_s) + 4], resp = 0;
        int32_t pi32 = player_i;
        memcpy(req, &e, sizeof(e));
        memcpy(req + sizeof(e), &pi32, 4);
        int r = g_mp_decision_hook(player_i, MP_DEC_ELECTION_ACCEPT, req, (int)sizeof(req), &resp, 1);
        if (r >= 1) { return resp != 0; }
    }
    return false;
}

